const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json || {};
return [{ json: Object.assign({}, r, { data: data }) }];

const r = $json || {};
const d = r.data || {};
const year = r.year || new Date().getFullYear();
const client = (r.client || '').toString();
const brand = client ? client : 'Security Awareness';
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function arr(x){ return Array.isArray(x)?x:(x==null||x===''?[]:[x]); }
const MON = ['january','february','march','april','may','june','july','august','september','october','november','december'];
let months = arr(d.months);
if(!months.length){ months = MON.map(function(m){ return { month:m, theme:'', focus:'', channels:[], keyDates:[], ideas:[] }; }); }
function midx(name){ var n=String(name||'').toLowerCase().slice(0,3); for(var k=0;k<12;k++){ if(MON[k].slice(0,3)===n) return k; } return -1; }

const CSS = "@page{size:A4;margin:14mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#14202b} "
+".hd{border-bottom:3px solid #0E7C86;padding-bottom:10px;margin-bottom:14px} .hd .k{color:#0E7C86;letter-spacing:3px;font-size:12px;font-weight:800;text-transform:uppercase} "
+".hd h1{margin:4px 0 0;font-size:26px;color:#0E2233} .hd .s{color:#5A6472;font-size:13px;margin-top:4px} "
+"table{width:100%;border-collapse:collapse;font-size:11px} th{background:#0E2233;color:#fff;text-align:left;padding:7px 8px;font-size:11px} "
+"td{border:1px solid #e2e6ec;padding:7px 8px;vertical-align:top;line-height:1.4} tr:nth-child(even) td{background:#f7fafb} "
+".mo{font-weight:800;color:#0E7C86;white-space:nowrap} .th{font-weight:700;color:#0E2233} "
+"ul{margin:0;padding-left:15px} li{margin:2px 0} .foot{margin-top:14px;border-top:1px solid #e2e6ec;padding-top:8px;color:#8a98a4;font-size:10px;display:flex;justify-content:space-between}";
function cell(list){ list=arr(list); return list.length?('<ul>'+list.map(function(x){return '<li>'+esc(x)+'</li>';}).join('')+'</ul>'):'—'; }
let rows = months.slice(0,12).map(function(m){
  return '<tr><td class="mo">'+esc(m.month||'')+'</td><td><span class="th">'+esc(m.theme||'')+'</span><br><span style="color:#5A6472">'+esc(m.focus||'')+'</span></td><td>'+cell(m.channels)+'</td><td>'+cell(m.keyDates)+'</td><td>'+cell(m.ideas)+'</td></tr>';
}).join('');
const html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'
+'<div class="hd"><div class="k">Awareness Campaign Calendar</div><h1>'+esc(brand)+' · '+year+'</h1>'
+(r.focus?'<div class="s">Focus: '+esc(r.focus)+' · Audience: '+esc(r.audience||'All staff')+'</div>':'<div class="s">Audience: '+esc(r.audience||'All staff')+'</div>')+'</div>'
+'<table><thead><tr><th>Month</th><th>Theme &amp; focus</th><th>Channels</th><th>Key dates</th><th>Activity ideas</th></tr></thead><tbody>'+rows+'</tbody></table>'
+'<div class="foot"><span>'+esc(brand)+' · AI-generated — review &amp; adapt before scheduling</span><span>'+year+'</span></div></body></html>';

// .ics — one all-day VEVENT per month (launch of the month theme)
function pad(n){ return (n<10?'0':'')+n; }
const stamp = new Date().toISOString().replace(/[-:]/g,'').replace(/\.\d+Z$/,'Z');
let ics = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//Jarvis//Awareness Calendar//EN','CALSCALE:GREGORIAN','METHOD:PUBLISH'];
months.slice(0,12).forEach(function(m,pos){ var mi=midx(m.month); if(mi<0)mi=pos; var dt=String(year)+pad(mi+1)+'01'; var dtend=String(year)+pad(mi+1)+'02'; var theme=(m.theme||('Month '+(mi+1)+' awareness')); ics.push('BEGIN:VEVENT'); ics.push('UID:jarvis-'+year+'-'+pad(mi+1)+'@awareness'); ics.push('DTSTAMP:'+stamp); ics.push('DTSTART;VALUE=DATE:'+dt); ics.push('DTEND;VALUE=DATE:'+dtend); ics.push('SUMMARY:'+String(theme).replace(/[\r\n]+/g,' ')); var desc=[m.focus, (arr(m.channels).length?('Channels: '+arr(m.channels).join(', ')):''), (arr(m.ideas).length?('Ideas: '+arr(m.ideas).join('; ')):'')].filter(Boolean).join(' \\n '); if(desc) ics.push('DESCRIPTION:'+desc.replace(/[\r\n]+/g,' ')); ics.push('END:VEVENT'); });
ics.push('END:VCALENDAR');
const icsStr = ics.join('\r\n')+'\r\n';

return [{ json: { html: html, ics: icsStr, topic: r.topic||('Awareness campaign '+year), date: r.date, fileSafe: r.fileSafe||('campaign-'+year), outDir: 'calendar', filePrefix: 'calendar' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'calendar');
const base = (meta.filePrefix || 'calendar') + '-' + (meta.fileSafe || 'item') + '-' + meta.date;
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
try { if (buf) fs.writeFileSync(dir + '/' + base + '.pdf', buf); } catch (e) {}
try { if (meta.ics) fs.writeFileSync(dir + '/' + base + '.ics', meta.ics); } catch (e) {}
const out = { json: { ok: !!buf, pdf: dir + '/' + base + '.pdf', ics: dir + '/' + base + '.ics', topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = base + '.pdf'; out.binary = { data: b.data }; } } catch (e) {}
return [out];
